const cfg = $('Sweep Config').first().json;
const ttlHours = Number(cfg.ttlHours) > 0 ? Number(cfg.ttlHours) : 24;
const dryRun = cfg.dryRun === true;
const ttlMs = ttlHours * 3600000;
const now = Date.now();

const sources = [
  { platform: 'whatsapp', base: 'https://wappi.pro/api', payload: $('List WA Profiles').first().json },
  { platform: 'telegram', base: 'https://wappi.pro/tapi', payload: $('List TG Profiles').first().json }
];

// first-seen ledger: { '<platform>:<profile_id>': epochMs } — persists across
// production runs; the TTL clock starts when the sweep FIRST observes a profile
// unauthorized (Wappi exposes no creation timestamp).
const staticData = $getWorkflowStaticData('global');
if (typeof staticData.firstSeen !== 'object' || staticData.firstSeen === null) { staticData.firstSeen = {}; }
const firstSeen = staticData.firstSeen;

function parseTs(v) {
  if (!v || typeof v !== 'string') { return null; }
  const t = Date.parse(v);
  if (isNaN(t) || t <= 0) { return null; }
  return t;
}

const stats = { ranAt: new Date(now).toISOString(), mode: dryRun ? 'DRY RUN' : 'live', dryRun: dryRun, ttlHours: ttlHours, platforms: {}, candidateCount: 0, wouldDelete: [], skipped: [], ledgerSize: 0 };
const candidates = [];
const liveKeys = new Set();

for (const src of sources) {
  if (!src.payload || src.payload.status !== 'done') {
    throw new Error('Wappi profile list for ' + src.platform + ' did not return status done — aborting sweep, nothing deleted. Payload: ' + JSON.stringify(src.payload || null).slice(0, 300));
  }
  const profiles = Array.isArray(src.payload.profiles) ? src.payload.profiles : [];
  const ps = { total: profiles.length, authorized: 0, unauthorized: 0, newlyTracked: 0, underTtl: 0, alreadyDeleted: 0, candidates: 0 };

  for (const p of profiles) {
    const id = String(p.profile_id || '').trim();
    if (!id) { stats.skipped.push({ platform: src.platform, name: p.name || '', reason: 'empty profile_id' }); continue; }
    const key = src.platform + ':' + id;
    liveKeys.add(key);

    if (p.deleted_at) { ps.alreadyDeleted += 1; delete firstSeen[key]; continue; }
    if (p.authorized === true) { ps.authorized += 1; delete firstSeen[key]; continue; }
    if (p.authorized !== false) { stats.skipped.push({ platform: src.platform, profileId: id, reason: 'authorized flag missing or ambiguous — never delete on ambiguity' }); continue; }

    ps.unauthorized += 1;
    if (!(key in firstSeen)) { firstSeen[key] = now; ps.newlyTracked += 1; }

    const ageMs = now - firstSeen[key];
    const authTs = parseTs(p.authorized_at);
    const logoutTs = parseTs(p.logouted_at);
    const recentlyActive = (authTs !== null && now - authTs < ttlMs) || (logoutTs !== null && now - logoutTs < ttlMs);

    if (ageMs < ttlMs || recentlyActive) { ps.underTtl += 1; continue; }

    ps.candidates += 1;
    candidates.push({
      platform: src.platform,
      profileId: id,
      profileName: p.name || '',
      firstSeenAt: new Date(firstSeen[key]).toISOString(),
      trackedHours: Math.round(ageMs / 360000) / 10,
      statusUrl: src.base + '/sync/get/status?profile_id=' + encodeURIComponent(id),
      deleteUrl: src.base + '/profile/delete?profile_id=' + encodeURIComponent(id)
    });
  }
  stats.platforms[src.platform] = ps;
}

// GC ledger entries for profiles that no longer exist in the account
for (const key of Object.keys(firstSeen)) {
  if (!liveKeys.has(key)) { delete firstSeen[key]; }
}
stats.ledgerSize = Object.keys(firstSeen).length;
stats.candidateCount = candidates.length;

if (dryRun) {
  stats.wouldDelete = candidates;
  return [{ json: Object.assign({}, stats, { candidates: [] }) }];
}
return [{ json: Object.assign({}, stats, { candidates: candidates }) }];

const cand = $('Split Candidates').item.json;
const resp = $json;
// Wappi get/status has NO status:"done" field (unlike add/delete/list) — a valid
// response is identified by a real boolean `authorized` echoing our profile_id
// (the id match also guards against Wappi's known concurrent-response crossing).
const verifyOk = typeof resp.authorized === 'boolean' && resp.profile_id === cand.profileId;
return { json: Object.assign({}, cand, {
  verifyOk: verifyOk,
  verifyAuthorized: verifyOk ? resp.authorized : null,
  confirmedOrphan: verifyOk && resp.authorized === false
}) };

const cand = $('Confirm Orphan').item.json;
const resp = $json;
return { json: {
  platform: cand.platform,
  profileId: cand.profileId,
  profileName: cand.profileName,
  firstSeenAt: cand.firstSeenAt,
  trackedHours: cand.trackedHours,
  deleted: resp.status === 'done',
  deleteResponse: resp
} };

const stats = $('Plan Sweep').first().json;
const results = $input.all().map(function (i) { return i.json; });
const deleted = results.filter(function (r) { return r.deleted; });
const failed = results.filter(function (r) { return !r.deleted; });
return [{ json: {
  ranAt: stats.ranAt,
  mode: stats.mode,
  ttlHours: stats.ttlHours,
  platforms: stats.platforms,
  deletedCount: deleted.length,
  deleted: deleted,
  failedCount: failed.length,
  failed: failed
} }];
